begin;
update segments s set segment_key='1FN_xHL-u-Q:0:51', segment_title='Practice Strategy: Choosing One Variable', timestamp_label='0:00–0:51', start_url='https://www.youtube.com/watch?v=1FN_xHL-u-Q&t=0s', use_when='the player needs a clearer way to organize a technical practice task', teaching_summary='Narrow the task to one variable, slow it enough to observe, and repeat only long enough to learn something. The goal is not more repetition; it is clearer feedback.', problem_statement='practice is too broad to produce usable feedback', common_failure_mode='repeating the whole passage without isolating the cause of the problem', suggested_experiment='Choose one small unit, change one variable, and write down what improved before moving on.', reflection_prompt='Did the smaller experiment reveal a specific next move?', review_status='ai_proposed', is_public=false, quality_score=0.920, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='1FN_xHL-u-Q__chunk_0001__000000-000300.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: Okay, I was asked by twilightflame91 to do a video on three octave scales and I have great need to repent because I don''t usually practice scales.' from videos v where s.video_id=v.id and v.youtube_video_id='1FN_xHL-u-Q' and s.start_seconds=0 and s.end_seconds=51;
update segments s set segment_key='1FN_xHL-u-Q:46:87', segment_title='Intonation: Finding a Clearer Core', timestamp_label='0:46–1:27', start_url='https://www.youtube.com/watch?v=1FN_xHL-u-Q&t=46s', use_when='the player cannot reliably hear, place, or sustain the pitch', teaching_summary='Slow the material enough to hear each pitch in context. Use a stable tone and relaxed setup so the ear can correct the note instead of compensating for tension.', problem_statement='pitch placement is inconsistent', common_failure_mode='trying to correct pitch after a tense or unclear attack', suggested_experiment='Play the passage slowly, stop on each target pitch, and compare it to the resonance or reference pitch before continuing.', reflection_prompt='Could you hear the pitch settle before moving to the next note?', review_status='ai_proposed', is_public=false, quality_score=0.920, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='1FN_xHL-u-Q__chunk_0001__000000-000300.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: So what I''m concentrating on here is the intonation and the consistency of sound.' from videos v where s.video_id=v.id and v.youtube_video_id='1FN_xHL-u-Q' and s.start_seconds=46 and s.end_seconds=87;
update segments s set segment_key='1FN_xHL-u-Q:110:137', segment_title='Performance Nerves: Reducing Pressure Tension', timestamp_label='1:50–2:17', start_url='https://www.youtube.com/watch?v=1FN_xHL-u-Q&t=110s', use_when='tension or shaking appears under pressure', teaching_summary='Treat the physical response as a cue to reduce unnecessary effort. Rehearse the passage with a simple, observable release point rather than trying to suppress nerves by force.', problem_statement='pressure is increasing physical tension', common_failure_mode='trying to overpower shaking with more grip or force', suggested_experiment='Before each attempt, choose one release cue—jaw, shoulder, thumb, or bow hand—and assess only whether it stayed available under pressure.', reflection_prompt='Did the chosen release cue remain available when you simulated performance pressure?', review_status='ai_proposed', is_public=false, quality_score=0.880, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='1FN_xHL-u-Q__chunk_0001__000000-000300.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: high enough and so if you''re not lifting high enough there''s more chance for things to to shake in your arm particularly when you''re nervous.' from videos v where s.video_id=v.id and v.youtube_video_id='1FN_xHL-u-Q' and s.start_seconds=110 and s.end_seconds=137;
update segments s set segment_key='1FN_xHL-u-Q:315:370', segment_title='Intonation: Keeping the Motion Relaxed', timestamp_label='5:15–6:10', start_url='https://www.youtube.com/watch?v=1FN_xHL-u-Q&t=315s', use_when='the player cannot reliably hear, place, or sustain the pitch', teaching_summary='Slow the material enough to hear each pitch in context. Use a stable tone and relaxed setup so the ear can correct the note instead of compensating for tension.', problem_statement='pitch placement is inconsistent', common_failure_mode='trying to correct pitch after a tense or unclear attack', suggested_experiment='Play the passage slowly, stop on each target pitch, and compare it to the resonance or reference pitch before continuing.', reflection_prompt='Could you hear the pitch settle before moving to the next note?', review_status='ai_proposed', is_public=false, quality_score=0.920, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='1FN_xHL-u-Q__chunk_0002__000300-000600.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: Because if you can do a whole three octave scale and keep the tone consistent and keep it in tune and also stay relaxed here, well think about how that translates into a song.' from videos v where s.video_id=v.id and v.youtube_video_id='1FN_xHL-u-Q' and s.start_seconds=315 and s.end_seconds=370;
update segments s set segment_key='1FN_xHL-u-Q:370:404', segment_title='Scale Practice: Giving the Scale One Job', timestamp_label='6:10–6:44', start_url='https://www.youtube.com/watch?v=1FN_xHL-u-Q&t=370s', use_when='the player needs a focused technical routine rather than a passive run-through', teaching_summary='Use scales to isolate one concrete variable—pitch, tone, rhythm, relaxation, or shifting—rather than simply getting through the notes.', problem_statement='scale practice lacks a clear technical purpose', common_failure_mode='playing through the scale without listening for one defined result', suggested_experiment='Choose one variable for a single scale repetition, name it aloud, and evaluate only that variable before repeating.', reflection_prompt='Could you name one specific improvement or problem after the repetition?', review_status='ai_proposed', is_public=false, quality_score=0.880, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='1FN_xHL-u-Q__chunk_0002__000300-000600.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: Well if you''ve been practicing it correctly, let''s translate that scale I was just playing into this arpeggio.' from videos v where s.video_id=v.id and v.youtube_video_id='1FN_xHL-u-Q' and s.start_seconds=370 and s.end_seconds=404;
