update segments s set segment_key='1FN_xHL-u-Q:600:658', segment_title='Accent: Smoothing the Bow Change', timestamp_label='10:00–10:58', start_url='https://www.youtube.com/watch?v=1FN_xHL-u-Q&t=600s', use_when='the player’s accents sound heavy, late, or over-sustained', teaching_summary='Place energy at the front of the note, then let the sound continue without extra pressure. The accent is an arrival and release, not a prolonged push.', problem_statement='the accent is not speaking cleanly', common_failure_mode='maintaining pressure after the initial attack', suggested_experiment='Play one accented note followed by a sustained note, keeping the added energy only at the beginning of the first note.', reflection_prompt='Did the front of the note speak while the rest of the sound stayed free?', review_status='ai_proposed', is_public=false, quality_score=0.920, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='1FN_xHL-u-Q__chunk_0003__000600-000829.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: I haven''t done a very good job of this in this video, but it''s important also to make sure that your bow changes are smooth.' from videos v where s.video_id=v.id and v.youtube_video_id='1FN_xHL-u-Q' and s.start_seconds=600 and s.end_seconds=658;
