update segments s set segment_key='EKeY_En_46g:71:116', segment_title='Bow Hold: Finding a Flexible Hold', timestamp_label='1:11–1:56', start_url='https://www.youtube.com/watch?v=EKeY_En_46g&t=71s', use_when='the player’s bow hand feels tight, awkward, or unable to stay flexible', teaching_summary='Use a balanced hold that supports the bow without squeezing it. Let the fingers remain responsive so the hand can absorb motion rather than fight it.', problem_statement='the bow hand is over-gripping', common_failure_mode='trying to control the bow by locking the fingers and thumb', suggested_experiment='Play slow open strings while allowing the fingers to stay curved and mobile; notice where pressure enters the thumb or pinky.', reflection_prompt='Did the bow feel easier to steer when the hand stayed flexible?', review_status='ai_proposed', is_public=false, quality_score=0.920, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='EKeY_En_46g__chunk_0001__000000-000300.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: So my bow hold typically from this angle ends up like this.' from videos v where s.video_id=v.id and v.youtube_video_id='EKeY_En_46g' and s.start_seconds=71 and s.end_seconds=116;
update segments s set segment_key='EKeY_En_46g:109:168', segment_title='Shifting: Organizing the Shift', timestamp_label='1:49–2:48', start_url='https://www.youtube.com/watch?v=EKeY_En_46g&t=109s', use_when='the player is missing, delaying, or over-controlling a position change', teaching_summary='Treat the shift as a coordinated move rather than a reach for the destination note. Keep the hand and thumb released enough to travel, then check the arrival pitch after the motion is free.', problem_statement='the position change is late, tense, or unreliable', common_failure_mode='locking the hand or thumb and trying to force the destination pitch', suggested_experiment='Practice the shift slowly with an audible guide note, keeping the thumb soft; then remove the guide only after the travel feels free.', reflection_prompt='Did the hand arrive more calmly and accurately when the thumb and arm stayed released?', review_status='ai_proposed', is_public=false, quality_score=0.880, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='EKeY_En_46g__chunk_0001__000000-000300.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: In the next part, try to aim for the shift.' from videos v where s.video_id=v.id and v.youtube_video_id='EKeY_En_46g' and s.start_seconds=109 and s.end_seconds=168;
