update segments s set segment_key='Fic0zak8K5Y:772:780', segment_title='Bow Speed: Matching Speed to the Sound', timestamp_label='12:52–13:00', start_url='https://www.youtube.com/watch?v=Fic0zak8K5Y&t=772s', use_when='the player’s sound is choked, thin, or hard to control dynamically', teaching_summary='Let bow travel rate match the amount of sound needed. Change speed deliberately before adding pressure so the string can continue to vibrate freely.', problem_statement='bow speed and desired sound are mismatched', common_failure_mode='adding pressure when more or less travel speed is the missing variable', suggested_experiment='Play the same note at three bow speeds with similar contact point and weight, then identify which speed supports the intended sound.', reflection_prompt='Did changing speed solve the sound problem more cleanly than pressing harder?', review_status='ai_proposed', is_public=false, quality_score=0.720, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='Fic0zak8K5Y__chunk_0003__000600-000900.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: so the, now where I am on the middle of the page.' from videos v where s.video_id=v.id and v.youtube_video_id='Fic0zak8K5Y' and s.start_seconds=772 and s.end_seconds=780;
