update segments s set segment_key='Qs-tFga-tVg:305:357', segment_title='Intonation: Coordinating the String Change', timestamp_label='5:05–5:57', start_url='https://www.youtube.com/watch?v=Qs-tFga-tVg&t=305s', use_when='the player cannot reliably hear, place, or sustain the pitch', teaching_summary='Slow the material enough to hear each pitch in context. Use a stable tone and relaxed setup so the ear can correct the note instead of compensating for tension.', problem_statement='pitch placement is inconsistent', common_failure_mode='trying to correct pitch after a tense or unclear attack', suggested_experiment='Play the passage slowly, stop on each target pitch, and compare it to the resonance or reference pitch before continuing.', reflection_prompt='Could you hear the pitch settle before moving to the next note?', review_status='ai_proposed', is_public=false, quality_score=0.920, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='Qs-tFga-tVg__chunk_0002__000300-000511.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: At this point, this is measure 15, I like to shift up to third position and using the A string to mask that shift so you can''t hear it.' from videos v where s.video_id=v.id and v.youtube_video_id='Qs-tFga-tVg' and s.start_seconds=305 and s.end_seconds=357;
update segments s set segment_key='Qs-tFga-tVg:328:376', segment_title='Practice Strategy: Slowing Down to Hear the Result', timestamp_label='5:28–6:16', start_url='https://www.youtube.com/watch?v=Qs-tFga-tVg&t=328s', use_when='the player needs a clearer way to organize a technical practice task', teaching_summary='Narrow the task to one variable, slow it enough to observe, and repeat only long enough to learn something. The goal is not more repetition; it is clearer feedback.', problem_statement='practice is too broad to produce usable feedback', common_failure_mode='repeating the whole passage without isolating the cause of the problem', suggested_experiment='Choose one small unit, change one variable, and write down what improved before moving on.', reflection_prompt='Did the smaller experiment reveal a specific next move?', review_status='ai_proposed', is_public=false, quality_score=0.920, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='Qs-tFga-tVg__chunk_0002__000300-000511.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: So the only advice I can really give you there is because it''s so quick and so fast, make sure you practice it very slowly to begin with.' from videos v where s.video_id=v.id and v.youtube_video_id='Qs-tFga-tVg' and s.start_seconds=328 and s.end_seconds=376;
