update segments s set segment_key='neMlvsSMNEI:141:179', segment_title='Bow Changes: Smoothing the Bow Change', timestamp_label='2:21–2:59', start_url='https://www.youtube.com/watch?v=neMlvsSMNEI&t=141s', use_when='the player hears bumps, accents, or tension at direction changes', teaching_summary='Prepare the change before the bow reverses so the sound can continue through the turn. Keep the hand and arm coordinated rather than making a separate abrupt motion at the change.', problem_statement='bow changes interrupt the line', common_failure_mode='waiting until the last instant and forcing a directional reversal', suggested_experiment='Play two slow bows on one note and make the reversal as quietly as possible, then transfer the same feeling into the passage.', reflection_prompt='Did the direction change become less audible and less tense?', review_status='ai_proposed', is_public=false, quality_score=0.920, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='neMlvsSMNEI__chunk_0001__000000-000300.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: Okay, the other trick to get that slur to come in correctly or sound correct is to not start sliding until after your bow change, so you get that effect.' from videos v where s.video_id=v.id and v.youtube_video_id='neMlvsSMNEI' and s.start_seconds=141 and s.end_seconds=179;
