update segments s set segment_key='o-5jCSWJKwc:323:358', segment_title='Bow Relaxation: Keeping the Motion Relaxed', timestamp_label='5:23–5:58', start_url='https://www.youtube.com/watch?v=o-5jCSWJKwc&t=323s', use_when='the player grips the bow, feels rigid, or notices unwanted shaking', teaching_summary='Release excess grip so the bow can travel, rebound, and transmit arm weight without resistance. Look for ease in the hand before trying to add speed or volume.', problem_statement='bow-hand tension is interfering with control', common_failure_mode='using finger pressure to compensate for uncertainty in the stroke', suggested_experiment='Play a slow repeated stroke with the hand as quiet as possible, then loosen one finger at a time until the bow feels supported but not squeezed.', reflection_prompt='Did the sound or rebound improve when the hand used less effort?', review_status='ai_proposed', is_public=false, quality_score=0.920, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='o-5jCSWJKwc__chunk_0002__000300-000600.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: So I''m going to try to put that into practice and then what I do is I relax and then keep on my bow because if you don''t pull your bow you don''t get any sound.' from videos v where s.video_id=v.id and v.youtube_video_id='o-5jCSWJKwc' and s.start_seconds=323 and s.end_seconds=358;
update segments s set segment_key='oVU8RYnnrzg:13:27', segment_title='Intonation: Listening Before Correcting', timestamp_label='0:13–0:27', start_url='https://www.youtube.com/watch?v=oVU8RYnnrzg&t=13s', use_when='the player cannot reliably hear, place, or sustain the pitch', teaching_summary='Slow the material enough to hear each pitch in context. Use a stable tone and relaxed setup so the ear can correct the note instead of compensating for tension.', problem_statement='pitch placement is inconsistent', common_failure_mode='trying to correct pitch after a tense or unclear attack', suggested_experiment='Play the passage slowly, stop on each target pitch, and compare it to the resonance or reference pitch before continuing.', reflection_prompt='Could you hear the pitch settle before moving to the next note?', review_status='ai_proposed', is_public=false, quality_score=0.770, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='oVU8RYnnrzg__chunk_0001__000000-000300.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: You have a lot of mobility in your left hand to move on those really fast runs and getting your intonation good.' from videos v where s.video_id=v.id and v.youtube_video_id='oVU8RYnnrzg' and s.start_seconds=13 and s.end_seconds=27;
update segments s set segment_key='oVU8RYnnrzg:139:170', segment_title='Bow Speed: Matching Speed to the Sound', timestamp_label='2:19–2:50', start_url='https://www.youtube.com/watch?v=oVU8RYnnrzg&t=139s', use_when='the player’s sound is choked, thin, or hard to control dynamically', teaching_summary='Let bow travel rate match the amount of sound needed. Change speed deliberately before adding pressure so the string can continue to vibrate freely.', problem_statement='bow speed and desired sound are mismatched', common_failure_mode='adding pressure when more or less travel speed is the missing variable', suggested_experiment='Play the same note at three bow speeds with similar contact point and weight, then identify which speed supports the intended sound.', reflection_prompt='Did changing speed solve the sound problem more cleanly than pressing harder?', review_status='ai_proposed', is_public=false, quality_score=0.880, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='oVU8RYnnrzg__chunk_0001__000000-000300.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: Regardless of which direction you''re moving your bow, this first stroke, which I think is an up bow, should receive the least amount of bow usage, of bow speed.' from videos v where s.video_id=v.id and v.youtube_video_id='oVU8RYnnrzg' and s.start_seconds=139 and s.end_seconds=170;
update segments s set segment_key='opNpw5mOowo:36:71', segment_title='Orchestral Balance: Choosing the Musical Role', timestamp_label='0:36–1:11', start_url='https://www.youtube.com/watch?v=opNpw5mOowo&t=36s', use_when='the player needs to fit the surrounding texture instead of overplaying', teaching_summary='Choose dynamic weight according to the role of the line. Let the ensemble hierarchy determine how much the part projects, even when the written part looks active.', problem_statement='the part is taking more space than the texture requires', common_failure_mode='treating every written gesture as a solo statement', suggested_experiment='Play the line once as a foreground voice and once as a supporting layer; identify which role best matches the imagined texture.', reflection_prompt='Could you hear the line’s role in the texture rather than only its individual notes?', review_status='ai_proposed', is_public=false, quality_score=0.880, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='opNpw5mOowo__chunk_0001__000000-000300.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: Okay, so the orchestra comes in, just has this...' from videos v where s.video_id=v.id and v.youtube_video_id='opNpw5mOowo' and s.start_seconds=36 and s.end_seconds=71;
