update segments s set segment_key='opNpw5mOowo:141:170', segment_title='Shifting: Slowing Down to Hear the Result', timestamp_label='2:21–2:50', start_url='https://www.youtube.com/watch?v=opNpw5mOowo&t=141s', use_when='the player is missing, delaying, or over-controlling a position change', teaching_summary='Treat the shift as a coordinated move rather than a reach for the destination note. Keep the hand and thumb released enough to travel, then check the arrival pitch after the motion is free.', problem_statement='the position change is late, tense, or unreliable', common_failure_mode='locking the hand or thumb and trying to force the destination pitch', suggested_experiment='Practice the shift slowly with an audible guide note, keeping the thumb soft; then remove the guide only after the travel feels free.', reflection_prompt='Did the hand arrive more calmly and accurately when the thumb and arm stayed released?', review_status='ai_proposed', is_public=false, quality_score=0.880, source_type='local_whisper_json_ai_editorial_pass', transcript_source_file='opNpw5mOowo__chunk_0001__000000-000300.json', notes='AI editorial pass from timestamped Whisper JSON. Keep ai_proposed and is_public=false until the original video segment is reviewed. Evidence cue: So when you get your violin up, give yourself a breath, and then when you breathe in, get your violin up, and then from this position, just slowly, very slowly start…' from videos v where s.video_id=v.id and v.youtube_video_id='opNpw5mOowo' and s.start_seconds=141 and s.end_seconds=170;
